<!-- иҙҰеҸ·еҜҶз Ғзҷ»еҪ•йЎө -->
<template>
	<view class="uni-content">
		<view class="login-logo">
			<image :src="logo"></image>
		</view>
		<!-- йЎ¶йғЁж–Үеӯ— -->
		<text class="title title-box">иҙҰеҸ·еҜҶз Ғзҷ»еҪ•</text>
		<uni-forms>
			<uni-forms-item name="username">
				<uni-easyinput :focus="focusUsername" @blur="focusUsername = false" class="input-box"
					:inputBorder="false" v-model="username" placeholder="иҜ·иҫ“е…ҘжүӢжңәеҸ·/з”ЁжҲ·еҗҚ/йӮ®з®ұ" />
			</uni-forms-item>
			<uni-forms-item name="password">
				<uni-easyinput :focus="focusPassword" @blur="focusPassword = false" class="input-box" clearable
					type="password" :inputBorder="false" v-model="password" placeholder="иҜ·иҫ“е…ҘеҜҶз Ғ" />
			</uni-forms-item>
		</uni-forms>
		<uni-captcha v-if="needCaptcha" focus ref="captcha" scene="login-by-pwd" v-model="captcha" />
		<!-- еёҰйҖүжӢ©жЎҶзҡ„йҡҗз§Ғж”ҝзӯ–еҚҸи®®з»„д»¶ -->
		<uni-id-pages-agreements scope="login" ref="agreements"></uni-id-pages-agreements>
		<button class="uni-btn" type="primary" @click="pwdLogin">зҷ»еҪ•</button>
		<!-- еҝҳи®°еҜҶз Ғ -->
		<view class="link-box">
			<view v-if="!config.isAdmin">
				<text class="forget">еҝҳи®°дәҶпјҹ</text>
				<text class="link" @click="toRetrievePwd">жүҫеӣһеҜҶз Ғ</text>
			</view>
			<text class="link" @click="toRegister">{{config.isAdmin ? 'жіЁеҶҢз®ЎзҗҶе‘ҳиҙҰеҸ·': 'жіЁеҶҢиҙҰеҸ·'}}</text>
			<!-- <text class="link" @click="toRegister" v-if="!config.isAdmin">жіЁеҶҢиҙҰеҸ·</text> -->
		</view>
		<!-- жӮ¬жө®зҷ»еҪ•ж–№ејҸз»„д»¶ -->
		<uni-id-pages-fab-login ref="uniFabLogin"></uni-id-pages-fab-login>
	</view>
</template>

<script>
	import mixin from '@/uni_modules/uni-id-pages/common/login-page.mixin.js';
	const uniIdCo = uniCloud.importObject("uni-id-co", {
		errorOptions: {
			type: 'toast'
		}
	})
	export default {
		mixins: [mixin],
		data() {
			return {
				"password": "",
				"username": "",
				"captcha": "",
				"needCaptcha": false,
				"focusUsername": false,
				"focusPassword": false,
				"logo": "/static/logo.png"
			}
		},
		onShow() {
			// #ifdef H5
			document.onkeydown = event => {
				var e = event || window.event;
				if (e && e.keyCode == 13) { //еӣһиҪҰй”®зҡ„й”®еҖјдёә13
					this.pwdLogin()
				}
			};
			// #endif
		},
		methods: {
			// йЎөйқўи·іиҪ¬пјҢжүҫеӣһеҜҶз Ғ
			toRetrievePwd() {
				let url = '/uni_modules/uni-id-pages/pages/retrieve/retrieve'
				//еҰӮжһңеҲҡеҘҪз”ЁжҲ·еҗҚиҫ“е…ҘжЎҶзҡ„еҖјдёәжүӢжңәеҸ·з ҒпјҢе°ұжҠҠе®ғдј еҲ°retrieveйЎөйқўпјҢж №жҚ®иҜҘжүӢжңәеҸ·жүҫеӣһеҜҶз Ғ
				if (/^1\d{10}$/.test(this.username)) {
					url += `?phoneNumber=${this.username}`
				}
				uni.navigateTo({
					url
				})
			},
			/**
			 * еҜҶз Ғзҷ»еҪ•
			 */
			pwdLogin() {
				if (!this.password.length) {
					this.focusPassword = true
					return uni.showToast({
						title: 'иҜ·иҫ“е…ҘеҜҶз Ғ',
						icon: 'none',
						duration: 3000
					});
				}
				if (!this.username.length) {
					this.focusUsername = true
					return uni.showToast({
						title: 'иҜ·иҫ“е…ҘжүӢжңәеҸ·/з”ЁжҲ·еҗҚ/йӮ®з®ұ',
						icon: 'none',
						duration: 3000
					});
				}
				if (this.needCaptcha && this.captcha.length != 4) {
					this.$refs.captcha.getImageCaptcha()
					return uni.showToast({
						title: 'иҜ·иҫ“е…ҘйӘҢиҜҒз Ғ',
						icon: 'none',
						duration: 3000
					});
				}

				if (this.needAgreements && !this.agree) {
					return this.$refs.agreements.popup(this.pwdLogin)
				}

				let data = {
					"password": this.password,
					"captcha": this.captcha
				}

				if (/^1\d{10}$/.test(this.username)) {
					data.mobile = this.username
				} else if (/@/.test(this.username)) {
					data.email = this.username
				} else {
					data.username = this.username
				}

				uniIdCo.login(data).then(e => {
					this.loginSuccess(e)
				}).catch(e => {
					if (e.errCode == 'uni-id-captcha-required') {
						this.needCaptcha = true
					} else if (this.needCaptcha) {
						//зҷ»еҪ•еӨұиҙҘпјҢиҮӘеҠЁйҮҚж–°иҺ·еҸ–йӘҢиҜҒз Ғ
						this.$refs.captcha.getImageCaptcha()
					}
				})
			},
			/* еүҚеҫҖжіЁеҶҢ */
			toRegister() {
				uni.navigateTo({
					url: this.config.isAdmin ? '/uni_modules/uni-id-pages/pages/register/register-admin' :
						'/uni_modules/uni-id-pages/pages/register/register',
					fail(e) {
						console.error(e);
					}
				})
			}
		}
	}
</script>

<style lang="scss" scoped>
	@import "@/uni_modules/uni-id-pages/common/login-page.scss";

	@media screen and (min-width: 690px) {
		.uni-content {
			height: auto;
		}
	}

	.forget {
		font-size: 12px;
		color: #8a8f8b;
	}

	.link-box {
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		flex-direction: row;
		justify-content: space-between;
		margin-top: 20px;
	}

	.link {
		font-size: 12px;
	}
</style>
